# NL ARD.  Amsterdam Singelgracht - Rotterdam Centraal
with detail = 2 {
    let ar = path("d2.nl.ard");

    with railway = :first :double :cat:dc15 :pax {
        with link = "line.nl.ARD" {
            track(ar[:asl.yz, :asl.yz + 6.31km]);
            line_label(:left:n, ar[:asl.yz + 6.3km] << 0.5md, "ARD");
            track(ar[:asl.yz + 6.29km, :haa]);
        }

        with link = "point.nl.Haarlem", railway = :station {
            track(ar[:haa, :hzu.yn + 0.1dl]);
            statdot(ar[:haa]);
            slabel(:right, ar[:haa] + (-1.5dt, -1.3dt), "Haarlem");
        }

        with link = "line.nl.ARD" {
            track(ar[:hzu.yn, :hzu.yn + 5.01km]);
            line_label(:right:e, ar[:hzu.yn + 5km] >> 0.5md,
                (0dt, -0.3dt), "ARD"
            );
            track(ar[:hzu.yn + 4.99km, :lei.yh - 4.29km]);
            line_label(:right:e, ar[:lei.yh - 4.3km] >> 0.5md, "ARD");
            track(ar[:lei.yh - 4.31km, :lei.yh]);
            track(ar[:lei.yh, :lei]);
        }

        with link = "point.nl.Leiden-Centraal", railway = :station {
            track(ar[:lei, :lei.yw]);
            statdot(ar[:lei]);
            slabel(:left, ar[:lei] + (-1.5dt, 0.1dt), "Leiden Centraal");
        }

        with link = "line.nl.ARD" {
            track(ar[:lei.yw, :lei.yw + 5.01km]);
            line_label(:right:se, ar[:lei.yw + 5km] >> 0.5md, "ARD");
            track(ar[:lei.yw + 4.99km, :dma]);
        }

        with link = "point.nl.Den-Haag-Mariahoeve", railway = :station {
            statdot(ar[:dma]);
            slabel(:right, ar[:dma] + (1.5dt, 2.5dt), "D.H. Mariahoeve");
        }

        with link = "line.nl.ARD" {
            track(ar[:dma, :dla]);
        }

        with link = "point.nl.Den-Haag-Laan-van-NOI", railway = :station {
            track(ar[:dla, :dla.yc]);
            statdot(ar[:dla]);
        }

        with link = "line.nl.ARD" {
            track(ar[:dla.yc, :dhs.yc]);
        }

        with link = "point.nl.Den-Haag-HS", railway = :station {
            track(ar[:dhs.yc, :dhs]);
            statdot(ar[:dhs]);
            slabel(:left, ar[:dhs] + (-1.8dt, 0.2dt), "D.H. HS");
        }

        with link = "line.nl.ARD" {
            track(ar[:dhs, :rit.a]);
            track(:tunnel, ar[:rit.a, :rit.f]);
            track(ar[:rit.f, :wit.a]);
            track(:tunnel, ar[:wit.a, :wit.f]);
            track(ar[:wit.f, :wit.f + 1.01km]);
            line_label(:right:e, ar[:wit.f + 1km] >> 0.5md, "ARD");
            track(ar[:wit.f + 0.99km, :sga.yh]);
        }

        with link = "point.nl.Schiedam-Centrum", railway = :station {
            track(ar[:sga.yh, :sch]);
            statdot(ar[:sch]);
            slabel(:ne, ar[:sch] + (-1.5dt, -0.3dt), "Schiedam Centrum");
        }

        with link = "line.nl.ARD" {
            track(ar[:sch, :rma]);
            track(ar[:rma, :sba.yn]);
            track(ar[:sba.yn, :rot.yu]);
        }

        with link = "point.nl.Rotterdam-Centraal", railway = :station {
            track(ar[:rot.yu, :rot]);
            statdot(ar[:rot]);
            slabel(:bottom, ar[:rot] + (0.2dt, 1.2dt), "R.C.");
        }
    }
}

